import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { logout } from "../authReducer";

function Admin() {
  const [teachers, setTeachers] = useState([]);
  const [students, setStudents] = useState([]);
  const [courses, setCourses] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  // Проверка роли и email администратора
  useEffect(() => {
    if (!user || user.role !== "admin" || user.email !== "admin@school.com") {
      alert("Access denied! Only admin@school.com can access this page.");
      dispatch(logout());
      navigate("/login");
    }
  }, [user, dispatch, navigate]);

  // Загрузка данных
  useEffect(() => {
    fetch("http://localhost:3001/users?role=teacher")
      .then((res) => res.json())
      .then((data) => setTeachers(data));
    fetch("http://localhost:3001/users?role=student")
      .then((res) => res.json())
      .then((data) => setStudents(data));
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data));
  }, []);

  // Удаление учителя
  async function handleDeleteTeacher(teacherId) {
    const response = await fetch(`http://localhost:3001/users/${teacherId}`, {
      method: "DELETE",
    });
    if (response.ok) {
      setTeachers(teachers.filter((t) => t.id !== teacherId));
    } else {
      alert("Failed to delete teacher");
    }
  }

  // Удаление ученика
  async function handleDeleteStudent(studentId) {
    const response = await fetch(`http://localhost:3001/users/${studentId}`, {
      method: "DELETE",
    });
    if (response.ok) {
      setStudents(students.filter((s) => s.id !== studentId));
    } else {
      alert("Failed to delete student");
    }
  }

  // Удаление курса
  async function handleDeleteCourse(courseId) {
    const response = await fetch(`http://localhost:3001/courses/${courseId}`, {
      method: "DELETE",
    });
    if (response.ok) {
      setCourses(courses.filter((c) => c.id !== courseId));
    } else {
      alert("Failed to delete course");
    }
  }

  return (
    <div>
      <h1>Admin Panel</h1>

      <h2>Teachers</h2>
      <ul>
        {teachers.map((teacher) => (
          <li key={teacher.id}>
            {teacher.name} ({teacher.email})
            <button onClick={() => handleDeleteTeacher(teacher.id)}>Delete</button>
          </li>
        ))}
      </ul>

      <h2>Students</h2>
      <ul>
        {students.map((student) => (
          <li key={student.id}>
            {student.name} ({student.email})
            <button onClick={() => handleDeleteStudent(student.id)}>Delete</button>
          </li>
        ))}
      </ul>

      <h2>Courses</h2>
      <ul>
        {courses.map((course) => (
          <li key={course.id}>
            {course.name} - {course.description}
            <button onClick={() => handleDeleteCourse(course.id)}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default Admin;
